        "question": [
          "what is the frequent action that came just before actions in category Cashout request?"
        ],
        "sql": [
          "WITH RankedActions AS (\n",
          "  SELECT\n",
          "    a1.HistoryID,\n",
          "    a1.actionname AS PrevAction,\n",
          "    a1.Occurred AS PrevOccurred,\n",
          "    a2.actionname AS NextAction,\n",
          "    a2.Occurred AS NextOccurred,\n",
          "    RANK() OVER (PARTITION BY a1.GCID ORDER BY a1.Occurred DESC) AS rnk\n",
          "  FROM\n",
          "    main.data_rooms.vw_fact_customeraction a1\n",
          "  INNER JOIN\n",
          "    main.data_rooms.vw_fact_customeraction a2\n",
          "    ON a1.GCID = a2.GCID AND a1.Occurred < a2.Occurred\n",
          "  WHERE\n",
          "    a2.Category = 'Cashout request' AND\n",
          "    a2.Occurred >= date_sub(current_date(), 14)\n",
          ")\n",
          "SELECT\n",
          "  PrevAction,\n",
          "  COUNT(*) AS Frequency\n",
          "FROM\n",
          "  RankedActions\n",
          "WHERE\n",
          "  rnk = 1\n",
          "GROUP BY\n",
          "  PrevAction\n",
          "ORDER BY\n",
          "  Frequency DESC\n",
          "LIMIT 1"
        ]
      }
    ]
